+        &self,
+        _state: &mut MiniState,
+        _cx: &MiniCx,
+        f: F,
+    ) -> Result<MiniHandle<Fut::Output>, MiniError>
+    where
+        F: FnOnce(MiniCx) -> Fut,
+        Fut: Future,
+    {
+        std::mem::drop(f(MiniCx));
+        Ok(MiniHandle(PhantomData))
+    }
+}

